      "path": "src/modules/projects/routes.js",
      "content": "const express = require('express');
const router = express.Router();
const { getProjects, createProject, getProjectById } = require('./service');

// Get all projects
router.get('/', async (req, res) => {
  try {
    const projects = await getProjects();
    res.json({ projects });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

// Create a new project
router.post('/', async (req, res) => {
  if (!req.body.name) return sendError(res, 400, 'BAD_REQUEST', 'Name is required');
  try {
    const project = await createProject({ name: req.body.name });
    res.status(201).json({ project });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

// Get a single project by ID
router.get('/:projectId', async (req, res) => {
  try {
    const project = await getProjectById(req.params.projectId);
    if (!project) return sendError(res, 404, 'NOT_FOUND', 'Project not found');
    res.json({ project });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

module.exports = router;"
