      "path": "src/modules/projects/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const projects = [];
exports.getProjects = () => {
  return projects;
};
exports.createProject = ({ name }) => {
  const project = { id: randomUUID(), name };
  projects.push(project);
  return project;
};
exports.getProjectById = (id) => {
  return projects.find(project => project.id === id);
};"
